import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.apache.commons.csv.CSVFormat;

import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    public void testIsQuoteCharacterSet_whenQuoteCharacterIsNull() throws Exception {
        CSVFormat csvFormat = CSVFormat.DEFAULT.withQuote((Character) null);

        // Use reflection to set private field quoteCharacter to null explicitly (redundant but safe)
        Field quoteCharacterField = CSVFormat.class.getDeclaredField("quoteCharacter");
        quoteCharacterField.setAccessible(true);
        quoteCharacterField.set(csvFormat, null);

        boolean result = csvFormat.isQuoteCharacterSet();

        assertFalse(result, "Expected isQuoteCharacterSet to be false when quoteCharacter is null");
    }

    @Test
    public void testIsQuoteCharacterSet_whenQuoteCharacterIsSet() throws Exception {
        CSVFormat csvFormat = CSVFormat.DEFAULT.withQuote('\''); // use single quote char

        // Use reflection to get the private field quoteCharacter and verify it is set
        Field quoteCharacterField = CSVFormat.class.getDeclaredField("quoteCharacter");
        quoteCharacterField.setAccessible(true);
        Character quoteChar = (Character) quoteCharacterField.get(csvFormat);

        assertNotNull(quoteChar, "quoteCharacter field should not be null");
        assertEquals('\'', quoteChar.charValue(), "quoteCharacter field should be set to '\''");

        boolean result = csvFormat.isQuoteCharacterSet();

        assertTrue(result, "Expected isQuoteCharacterSet to be true when quoteCharacter is set");
    }
}
